window.injectMieroMarks = function () {
  document.querySelectorAll('[data-miero-mark]').forEach(el => {
    if (el.dataset.mieroMarkInjected) return;
    el.innerHTML = window.MIERO_WORDMARK_SVG;
    el.dataset.mieroMarkInjected = '1';
  });
  document.querySelectorAll('[data-miero-script]').forEach(el => {
    if (el.dataset.mieroScriptInjected) return;
    el.innerHTML = window.MIERO_SCRIPT_SVG;
    el.dataset.mieroScriptInjected = '1';
  });
};
// Back-compat alias
window.injectMieroMark = window.injectMieroMarks;

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', window.injectMieroMarks);
} else {
  window.injectMieroMarks();
}
